                                <div className="warning-grid">
                                    <div className="warning-grid-row header">
                                        <div className="warning-col"><div className="warning-title">TROPICAL CYCLONE WARNING SIGNAL<div className="warning-sub">(based on DOST-PAGASA Weather Updates)</div></div></div>
                                        <div className="warning-col"><div className="weather-title">GENERAL WEATHER SITUATION<div className="warning-sub">(Actual Weather situation)</div></div></div>
                                    </div>
                                    <div className="warning-grid-row content">
                                        <div className="warning-col signals-col">
                                            <div className="warning-panel">
                                                <div className="warning-signals-list">{Object.entries(displayEvent.warning_signals || {}).map(([mun, signal]) => (<div key={mun} className="signal-item"><span className="mun-name">{mun}</span><span className="signal-number">Signal No. {signal}</span></div>))}</div>
                                                {Object.keys(displayEvent.warning_signals || {}).length === 0 && <div className="no-signals">No warning signals currently in effect.</div>}
                                            </div>
                                        </div>
                                        <div className="warning-col weather-col"><div className="warning-panel weather-panel"><div className="weather-text">{selectedOffice === 'PSTO-Region-1' ? displayWeather : (displayEvent.general_weather || 'No weather data reported')}</div></div></div>
                                    </div>
                                </div>

                                <div className="effects-section"><h4>📊 EFFECTS</h4>
                                    <div className="effects-panel"><div className="effects-list">
                                        {[
                                            { label: 'Related Incidents', value: displayEvent.related_incidents, remarkField: 'remark_related_incidents' },
                                            { label: 'Casualties', value: displayEvent.casualties, remarkField: 'remark_casualties' },
                                            { label: 'Power', value: displayEvent.power_status || '—', remarkField: 'remark_power_status' },
                                            { label: 'Communication', value: displayEvent.communication_lines || '—', remarkField: 'remark_communication_lines' },
                                            { label: 'Damage', value: displayEvent.damage_facilities || '—', remarkField: 'remark_damage_facilities' },
                                            { label: 'Work Suspension', value: displayEvent.work_suspension ? 'Yes' : 'No', remarkField: 'remark_work_suspension' },
                                            { label: 'Assistance', value: displayEvent.assistance_provided || '—', remarkField: 'remark_assistance_provided' },
                                        ].map((item) => (<div key={item.label} className="effect-row"><span className="effect-label">{item.label}:</span><span className="effect-value">{item.value}</span><span className="effect-remark">{displayEvent[item.remarkField] || '-'}</span></div>))}
                                    </div></div>
                                </div>

                                {/* View Mode - Damage Details */}
                                <div className="effects-section">
                                    <h4>🏗️ DAMAGE DETAILS</h4>
                                    <div className="effects-panel">
                                        {(displayEvent.damage_details || []).length > 0 ? (
                                            <div className="damage-view-list">
                                                {(displayEvent.damage_details || []).map((damage, idx) => (
                                                    <div key={idx} className="damage-view-item">
                                                        <span className="damage-view-desc">{damage.description}</span>
                                                        <span className="damage-view-cost">₱{damage.cost || 0}</span>
                                                        <span className={`status-badge ${damage.status?.toLowerCase() || 'reported'}`}>{damage.status || 'Reported'}</span>
                                                        {damage.image && <img src={damage.image} alt="Damage" className="damage-thumbnail" onClick={() => openImageModal(damage.image)} />}
                                                    </div>
                                                ))}
                                            </div>
                                        ) : (
                                            <p>No damage records reported.</p>
                                        )}
                                    </div>
                                </div>

                                {/* View Mode - Affected Staff */}
                                <div className="effects-section">
                                    <h4>👥 AFFECTED STAFF</h4>
                                    <div className="effects-panel">
                                        {(displayEvent.affected_staff || []).length > 0 ? (
                                            <div className="staff-view-list">
                                                {(displayEvent.affected_staff || []).map((staff, idx) => (
                                                    <div key={idx} className="staff-view-item">
                                                        <span className="staff-view-name">{staff.name}</span>
                                                        <span className="staff-view-area">{staff.area}</span>
                                                        <span className="staff-view-assistance">Assistance: {staff.assistance || 'None'}</span>
                                                        <span className={`status-badge ${staff.status?.toLowerCase() || 'active'}`}>{staff.status || 'Active'}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        ) : (
                                            <p>No staff records reported.</p>
                                        )}
                                    </div>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            </div>

            {showOfficeModal && selectedOffice && (
                <div className="modal-overlay" onClick={() => setShowOfficeModal(false)}>
                    <div className="modal-content event-details-modal" onClick={(e) => e.stopPropagation()}>
                        <div className="details-header"><div className="details-title">{selectedOffice} Summary</div><button className="modal-close" onClick={() => setShowOfficeModal(false)}>×</button></div>
                        <div className="detail-section"><div className="detail-section-title">Office Overview</div><div className="summary-panel"><p><strong>General Weather:</strong> {displayWeather}</p></div></div>
                        <div className="detail-section"><div className="detail-section-title">Updated Remarks</div><div className="summary-panel">
                            {officeStatusRemarks.length > 0 ? (
                                officeStatusRemarks.map((item) => (
                                    <div key={item.label} className="status-remark-row">
                                        <span className="status-remark-label">{item.label}:</span>
                                        <span className="status-remark-value">{item.value}</span>
                                        <span className="status-remark-text">{item.remark || 'No remarks'}</span>
                                    </div>
                                ))
                            ) : (
                                <p>No remarks provided.</p>
                            )}
                        </div></div>
                        {currentOfficeData.municipalities && currentOfficeData.municipalities.length > 0 && (
                            <div className="detail-section"><div className="detail-section-title">Municipalities</div><div className="scope-tags">{currentOfficeData.municipalities.map((mun) => <span key={mun} className="scope-tag">{mun}</span>)}</div></div>
                        )}
                        <div className="modal-buttons"><button onClick={() => setShowOfficeModal(false)}>Close</button></div>
                    </div>
                </div>
            )}
        </div>
    );

    // ----------------------------- SETTINGS MODAL -----------------------------
    const SettingsModal = () => (
        <div className="modal-overlay" onClick={() => setShowSettingsModal(false)}>
            <div className="modal-content large-modal" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h3>⚙️ System Settings</h3>
                    <button className="modal-close" onClick={() => setShowSettingsModal(false)}>×</button>
                </div>
                <div className="settings-grid">
                    <div className="settings-group">
                        <h4>General Settings</h4>
                        <div className="settings-item-row">
                            <label>System Name</label>
                            <input type="text" value={settingsData.systemName} onChange={(e) => setSettingsData({ ...settingsData, systemName: e.target.value })} />
                        </div>
                        <div className="settings-item-row">
                            <label>Default Alert Level</label>
                            <select value={settingsData.defaultAlertLevel} onChange={(e) => setSettingsData({ ...settingsData, defaultAlertLevel: e.target.value })}>
                                <option>RED</option><option>BLUE</option><option>WHITE</option>
                            </select>
                        </div>
                        <div className="settings-item-row">
                            <label>Auto Archive Days</label>
                            <input type="number" value={settingsData.autoArchiveDays} onChange={(e) => setSettingsData({ ...settingsData, autoArchiveDays: parseInt(e.target.value) || 7 })} min="1" max="30" />
                        </div>
                    </div>
                    <div className="settings-group">
                        <h4>Notification Settings</h4>
                        <div className="settings-item-row">
                            <label>Enable Notification Sound</label>
                            <input type="checkbox" checked={settingsData.notificationSound} onChange={(e) => setSettingsData({ ...settingsData, notificationSound: e.target.checked })} />
                        </div>
                        <div className="settings-item-row">
                            <label>Dark Mode</label>
                            <input type="checkbox" checked={settingsData.darkMode} onChange={(e) => {
                                setSettingsData({ ...settingsData, darkMode: e.target.checked });
                                document.body.classList.toggle('dark-mode', e.target.checked);
                            }} />
                        </div>
                    </div>
                    <div className="settings-group">
                        <h4>User Management</h4>
                        <div className="settings-item-row">
                            <button className="success" onClick={() => {
                                if (window.confirm('Update all users with current system settings?')) {
                                    updateAllUsers({
                                        // Add any user-wide updates here
                                    });
                                    showToast('All users updated.', 'success');
                                }
                            }}>Update All Users</button>
                        </div>
                        <div className="settings-item-row">
                            <button className="deploy-btn" onClick={() => {
                                if (window.confirm('Reset all user passwords to default?')) {
                                    setUsers(users.map(u => ({ ...u, password: u.role === 'SADMIN' ? 'admin123' : 'user123' })));
                                    addNotification('Passwords Reset', 'All user passwords have been reset to default.', 'warning');
                                    showToast('All passwords reset.', 'success');
                                }
                            }}>Reset All Passwords</button>
                        </div>
                    </div>
                    <div className="settings-group">
                        <h4>Data Management</h4>
                        <div className="settings-item-row">
                            <button onClick={exportData}>📤 Export All Data</button>
                            <label className="import-btn" style={{ marginLeft: '10px' }}>
                                <input type="file" onChange={importData} style={{ display: 'none' }} />
                                📥 Import Data
                            </label>
                        </div>
                        <div className="settings-item-row">
                            <button className="danger" onClick={resetToDefaultData}>⚠️ Reset to Default</button>
                        </div>
                    </div>
                </div>
                <div className="modal-buttons">
                    <button className="success" onClick={() => {
                        saveToStorage('dash_settings', settingsData);
                        showToast('Settings saved.', 'success');
                        setShowSettingsModal(false);
                    }}>Save Settings</button>
                    <button onClick={() => setShowSettingsModal(false)}>Close</button>
                </div>
            </div>
        </div>
    );

    // ----------------------------- MAIN RENDER -----------------------------
    return (
        <div className={`dashboard-container ${settingsData.darkMode ? 'dark-mode' : ''}`}>
            <div className="sidebar-new">
                <div className="sidebar-logo"><h2>DOST Region 1</h2><p>Disaster Management</p></div>
                <nav className="sidebar-nav">
                    <div className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}><span className="nav-icon">📊</span><span>Dashboard</span></div>
                    <div className={`nav-item ${activeMenu === 'typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('typhoon')}><span className="nav-icon">🌊</span><span>Typhoon</span></div>
                    <div className={`nav-item ${activeMenu === 'live-typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('live-typhoon')}><span className="nav-icon">🗺️</span><span>Live Typhoon (Panahon)</span></div>
                    <div className={`nav-item ${activeMenu === 'notifications' ? 'active' : ''}`} onClick={() => setActiveMenu('notifications')}><span className="nav-icon">🔔</span><span>Notifications {unreadCount > 0 && `(${unreadCount})`}</span></div>
                    {canApproveReports && <div className={`nav-item ${activeMenu === 'pending-reports' ? 'active' : ''}`} onClick={() => setActiveMenu('pending-reports')}><span className="nav-icon">📋</span><span>Pending Reports</span></div>}
                    {canManageUsers && <div className={`nav-item ${activeMenu === 'users' ? 'active' : ''}`} onClick={() => setActiveMenu('users')}><span className="nav-icon">👥</span><span>Users</span></div>}
                </nav>
                <div className="sidebar-footer">
                    <div className="user-info"><div className="user-greeting">Hello, {currentUser?.name || 'Admin'}</div><div className="user-role">{isSuperAdmin ? 'SUPER ADMIN' : (isAdmin ? 'ADMIN' : 'USER')}</div></div>
                    <div className="sidebar-settings">
                        <div className="settings-item" onClick={() => setShowSettingsModal(true)}>
                            <span className="settings-icon">⚙️</span>
                            <span>Settings</span>
                        </div>
                    </div>
                    <div className="user-actions"><div className="action-item logout" onClick={onLogout}>🚪 Logout</div></div>
                </div>
            </div>
            <div className="main-content">
                {isSuperAdmin && (
                    <div className="admin-toolbar">
                        <button onClick={resetToDefaultData}>Reset to Default Data</button>
                        <button onClick={exportData}>Export Data</button>
                        <label className="import-btn"><input type="file" onChange={importData} style={{ display: 'none' }} />Import Data</label>
                    </div>
                )}
                {activeMenu === 'dashboard' && <DashboardContent />}
                {activeMenu === 'typhoon' && <TyphoonContent />}
                {activeMenu === 'live-typhoon' && (
                    <div className="forecast-section card">
                        <h1>Live Typhoon (Panahon)</h1>
                        <div className="windy-embed-container"><iframe title="Panahon" src="https://www.panahon.gov.ph/" frameBorder="0" allowFullScreen /></div>
                    </div>
                )}
                {activeMenu === 'notifications' && <NotificationsContent />}
                {activeMenu === 'pending-reports' && canApproveReports && <PendingReportsContent />}
                {activeMenu === 'users' && canManageUsers && <UsersContent />}
            </div>
            {showReportModal && <SubmitReportModal />}
            {showReportReviewModal && <ReportReviewModal />}
            {showSettingsModal && <SettingsModal />}
            {showRejectModal && (
                <div className="modal-overlay" onClick={() => setShowRejectModal(false)}>
                    <div className="modal-content">
                        <h3>Reject Event</h3>
                        <textarea className="reject-reason-textarea" placeholder="Provide reason for rejection..." value={rejectReason} onChange={(e) => setRejectReason(e.target.value)} />
                        <div className="modal-buttons"><button className="danger" onClick={confirmRejectEvent}>Confirm Rejection</button><button onClick={() => setShowRejectModal(false)}>Cancel</button></div>
                    </div>
                </div>
            )}
            {showImageModal && imageModalSrc && (
                <div className="modal-overlay" onClick={closeImageModal}>
                    <div className="modal-content image-modal-content" onClick={e => e.stopPropagation()}>
                        <button className="modal-close" onClick={closeImageModal}>×</button>
                        <img src={imageModalSrc} alt="Enlarged" className="image-modal-img" />
                    </div>
                </div>
            )}
        </div>
    );
};

export default Dashboard;
